// The function should return True if all paragraph tags are valid, False otherwise.
function solve(html)
{
    let openingTags = []; // Initialize an array to keep track of the opening tags.
    let stack = []; // Initialize a stack to keep track of the opening and closing tags.
    for (let i = 0; i < html.length; i++)
    {
        if (html[i] === '<' && html[i + 1] === 'p')
        {
            // Push the index of the opening tag to the array.
            openingTags.push(i);
            stack.push('p'); // Push the opening tag to the stack.
        }
        else if (html[i] === '<' && html[i + 1] === '/') && html[i + 2] === 'p')
        {
            // If the tag is a closing tag, pop the stack and check if it matches the previous opening tag.
            let tag = stack.pop();
            if (tag !== 'p' || openingTags.length === 0)
            {
                return false;
            }
        }
    }
    // If all paragraph tags are valid, return True.
    return true;
}

