class Solution:
    def solve(self, html: str) -> bool:
        openingTags = []
        stack = []
        for i in range(len(html))
        {
            if html[i] == '<' and html[i + 1] == 'p'
            {
                # Push the index of the opening tag to the array.
                openingTags.append(i)
                stack.append('p') # Push the opening tag to the stack.
            }
            elif html[i] == '<' and html[i + 1] == '/' and html[i + 2] == 'p'
            {
                # If the tag is a closing tag, pop the stack and check if it matches the previous opening tag.
                tag = stack.pop()
                if tag != 'p' or len(openingTags) == 0
                {
                    return False
                }
            }
        }
        # If all paragraph tags are valid, return True.
        return True
